info:
Симулятор IoT-датчиков парковочных мест.
P-01..P-20 — постоянные, G-01..G-10 — гостевые.
Топик: smartresidency/parking/spots/{spot_number}

func:
var spot = msg.payload;
var motionMsg = {
    payload: JSON.stringify({ spot_number: spot, event_type: 'motion' }),
    topic: 'smartresidency/parking/spots/' + spot
};
var occupiedMsg = {
    payload: JSON.stringify({ spot_number: spot, event_type: 'occupied' }),
    topic: 'smartresidency/parking/spots/' + spot
};
node.warn('[parking] motion at ' + spot + ' — occupied in 10s');
return [motionMsg, occupiedMsg];

var spot = msg.payload;
msg.payload = JSON.stringify({ spot_number: spot, event_type: 'freed' });
msg.topic = 'smartresidency/parking/spots/' + spot;
node.warn('[parking] freed: ' + spot);
return msg;

var plate = (msg.payload || 'A777BC').toString().trim().toUpperCase();
var motionMsg = {
    payload: JSON.stringify({
        sensor_id: 'motion-parking',
        type: 'BARRIER_MOTION',
        gate_id: 'parking-gate',
        status: 'DETECTED',
        direction: 'IN'
    }),
    topic: 'smartresidency/barrier/motion'
};
var cameraMsg = {
    payload: JSON.stringify({
        sensor_id: 'camera-parking',
        type: 'BARRIER_CAMERA',
        gate_id: 'parking-gate',
        direction: 'IN',
        plate_number: plate,
        confidence: 0.96,
        status: 'RECOGNIZED'
    }),
    topic: 'smartresidency/barrier/camera/plate'
};
node.warn('[parking-gate] IN: plate=' + plate);
return [motionMsg, cameraMsg];

var permanent = [];
for (var i = 1; i <= 20; i++) permanent.push('P-' + (i < 10 ? '0' : '') + i);
var guest = [];
for (var j = 1; j <= 10; j++) guest.push('G-' + (j < 10 ? '0' : '') + j);
var all = permanent.concat(guest);
var spot = all[Math.floor(Math.random() * all.length)];
var eventType = Math.random() > 0.5 ? 'occupied' : 'freed';
node.warn('[parking-auto] spot=' + spot + ' event=' + eventType);
msg.payload = JSON.stringify({ spot_number: spot, event_type: eventType });
msg.topic = 'smartresidency/parking/spots/' + spot;
return msg;
